import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should compute base premium for a single sword", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0].premium).toBe(115);
    });
    it("should compute base premium for each item type (amulet, staff, potion)", () => {
      const quote = (type: string) =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [
            {
              op: "quote",
              items: [
                { type, material: "silver", enchantment: 0, cursed: false },
              ],
            },
          ],
        }).results[0].premium;

      expect(quote("amulet")).toBe(71);
      expect(quote("staff")).toBe(93);
      expect(quote("potion")).toBe(49);
    });
