import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

const quoteItems = (
  items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>,
  customer: { yearsWithMHPCO: number } = { yearsWithMHPCO: 0 },
) =>
  processScenario({
    customer,
    steps: [
      {
        op: "quote",
        items: items.map((item) => ({
          material: "steel",
          enchantment: 0,
          cursed: false,
          ...item,
        })),
      },
    ],
  }).results[0].premium;

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should compute base premium for a single sword", () => {
      expect(quoteItems([{ type: "sword" }])).toBe(115);
    });
    it("should compute base premium for each item type (amulet, staff, potion)", () => {
      expect(quoteItems([{ type: "amulet" }])).toBe(71);
      expect(quoteItems([{ type: "staff" }])).toBe(93);
      expect(quoteItems([{ type: "potion" }])).toBe(49);
    });
    it("should compute premium for a single component (rune)", () => {
      expect(quoteItems([{ type: "rune" }])).toBe(33);
    });
    it("should apply building block discount for 3 alike components", () => {
      expect(
        quoteItems([{ type: "rune" }, { type: "rune" }, { type: "rune" }])
      ).toBe(71);
    });
    it("should compute premium for multiple items", () => {
      expect(quoteItems([{ type: "sword" }, { type: "amulet" }])).toBe(181);
    });
    it.todo("should add cursed item surcharge of 50%");
    it.todo("should add high enchantment surcharge of 30% for enchantment >= 5");
    it.todo("should apply loyalty discount of 20% for customers >= 2 years");
    it.todo("should add initial assessment surcharge of 10% for first insurance");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should add 5G processing fee to every premium");
    it.todo("should round amounts in MHPCO's favor (round up)");
  });

  describe("Processing claims", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should reimburse regular damage fully minus deductible");
    it.todo("should reimburse dragon material damage at 100%");
    it.todo("should reimburse high enchantment (>= 8) damage at 50%");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across multiple claims on same policy");
  });
});

