  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const computeBasePremium = (items: any[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      const itemPremium = BASE_PREMIUMS[item.type];
      total += item.cursed ? itemPremium * 3 / 2 : itemPremium;
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    total += blocks * 60 + remainder * BASE_PREMIUMS[type];
  }
  return total;
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const basePremium = computeBasePremium(step.items);
    return { premium: Math.ceil(basePremium * 11 / 10 + 5) };
  });
  return { results };
};

